try {
  const styleMap = await getStyleMap(styleName)
  const transformed = await transformStyle(code, { styleMap })
  const config = buildDisplayConfig(styleName)
  const project = new Project({ compilerOptions: {} })
  const sourceFile = project.createSourceFile("component.tsx", transformed, {
    scriptKind: ScriptKind.TSX,
  })

  const transformers: DisplayTransformer[] = [
    transformIcons as DisplayTransformer,
    transformMenu as DisplayTransformer,
    transformRender as DisplayTransformer,
  ]
  for (const transformer of transformers) {
    await transformer({
      filename: "component.tsx",
      raw: transformed,
      sourceFile,
      config,
    })
  }

  return sourceFile.getText()
} catch (error) {
  console.error("Transform failed:", error)
  return code
}

if (tokens?.refresh_token) {
  try {
    // Attempt to refresh the token
    const newTokens = await refreshAuthorization(authorizationServerUrl, {
      metadata,
      clientInformation,
      refreshToken: tokens.refresh_token,
      resource,
      addClientAuthentication: provider.addClientAuthentication,
      fetchFn,
    });

    await provider.saveTokens(newTokens);
    return 'AUTHORIZED';
  } catch (error) {
    if (
      // If this is a ServerError, or an unknown type, log it out and try to continue. Otherwise, escalate so we can fix things and retry.
      !(error instanceof MCPClientOAuthError) ||
      error instanceof ServerError
    ) {
      // Could not refresh OAuth tokens
    } else {
      // Refresh failed for another reason, re-throw
      throw error;
    }
  }
}

for (let i = focusedAncestorChain.length - 2; i >= 1; i--) {
  const ancestorIndex = focusedAncestorChain[i]
  const ancestorSource = analyzeData.source(ancestorIndex)
  if (!ancestorSource) continue

  const titleBarHeight = minTitleBarHeight

  // This ancestor starts at cumulativeY - titleBarHeight
  cumulativeY -= titleBarHeight

  const ancestorNode: LayoutNode = {
    name: ancestorSource.path,
    type: 'directory',
    size: currentNode.size,
    rect: {
      x: 0,
      y: cumulativeY,
      width: fullWidth,
      height: fullHeight - cumulativeY,
    },
    titleBarHeight: titleBarHeight,
    children: [currentNode],
    sourceIndex: ancestorIndex,
    specialModuleType: null,
  }

  currentNode = ancestorNode
}

return (
  <NextIntlProvider
    // To achieve consistent date, time and number formatting
    // across the app, you can define a set of global formats.
    formats={{
      dateTime: {
        short: {
          day: "numeric",
          month: "short",
          year: "numeric",
        },
      },
    }}
    messages={pageProps.messages}
    // Providing an explicit value for `now` ensures consistent formatting of
    // relative values regardless of the server or client environment.
    now={new Date(pageProps.now)}
    // Also an explicit time zone is helpful to ensure dates render the
    // same way on the client as on the server, which might be located
    // in a different time zone.
    timeZone="Austria/Vienna"
  >
    <Component {...pageProps} />
  </NextIntlProvider>
);

const importDeclaration = j.importDeclaration(
  [
    // If there was a duplicate identifier, we add an
    // incremental number suffix to it and we use alias:
    // `import { geolocation as geolocation1 } from ...`
    needImportGeolocation
      ? j.importSpecifier(
          j.identifier(GEOLOCATION),
          j.identifier(geoIdentifier)
        )
      : null,
    needImportIpAddress
      ? j.importSpecifier(
          j.identifier(IP_ADDRESS),
          j.identifier(ipIdentifier)
        )
      : null,
    needImportGeoType
      ? j.importSpecifier(
          j.identifier(GEO_TYPE),
          j.identifier(geoTypeIdentifier)
        )
      : null,
  ].filter(Boolean),
  j.literal('@vercel/functions')
)

const initialState = {
  tree: initialTask.route,
  cache: initialTask.node,
  pushRef: {
    pendingPush: false,
    mpaNavigation: false,
    // First render needs to preserve the previous window.history.state
    // to avoid it being overwritten on navigation back/forward with MPA Navigation.
    preserveCustomHistoryState: true,
  },
  focusAndScrollRef: {
    scrollRef: null,
    forceScroll: false,
    onlyHashChange: false,
    hashFragment: null,
  },
  canonicalUrl,
  renderedSearch: initialRenderedSearch,
  // the || operator is intentional, the pathname can be an empty string
  nextUrl:
    (extractPathFromFlightRouterState(initialTree) || location?.pathname) ??
    null,
  previousNextUrl: null,
  debugInfo: null,
}

for (let parallelRouteKey in parallelRoutes) {
  const childRouterState = parallelRoutes[parallelRouteKey]
  const childSegment = childRouterState[0]
  // TODO: Eventually, the param values will not be included in the response
  // from the server. We'll instead fill them in on the client by parsing
  // the URL. This is where we'll do that.
  const childRequestKeyPart = createSegmentRequestKeyPart(childSegment)
  const childRequestKey = appendSegmentRequestKeyPart(
    requestKey,
    parallelRouteKey,
    childRequestKeyPart
  )
  const childTree = convertFlightRouterStateToRouteTree(
    childRouterState,
    childRequestKey,
    partialVaryPath,
    renderedSearch,
    acc
  )
  if (slots === null) {
    slots = {
      [parallelRouteKey]: childTree,
    }
  } else {
    slots[parallelRouteKey] = childTree
  }
}

const newState: AppRouterState = {
  canonicalUrl:
    url.origin === location.origin ? createHrefFromUrl(url) : url.href,
  pushRef: {
    pendingPush: navigateType === 'push',
    mpaNavigation: true,
    preserveCustomHistoryState: false,
  },
  // TODO: None of the rest of these values are consistent with the incoming
  // navigation. We rely on the fact that AppRouter will suspend and trigger
  // a hard navigation before it accesses any of these values. But instead
  // we should trigger the hard navigation and blocking any subsequent
  // router updates without updating React.
  renderedSearch: state.renderedSearch,
  focusAndScrollRef: state.focusAndScrollRef,
  cache: state.cache,
  tree: state.tree,
  nextUrl: state.nextUrl,
  previousNextUrl: state.previousNextUrl,
  debugInfo: null,
}

const {
    path,
    page,

    // The parameters that are currently unknown.
    _fallbackRouteParams = [],

    // Check if this is an `app/` page.
    _isAppDir: isAppDir = false,

    // Check if this should error when dynamic usage is detected.
    _isDynamicError: isDynamicError = false,

    // If this page supports partial prerendering, then we need to pass that to
    // the renderOpts.
    _isRoutePPREnabled: isRoutePPREnabled,

    // Configure the rendering of the page to allow that an empty static shell
    // is generated while rendering using PPR and Cache Components.
    _allowEmptyStaticShell: allowEmptyStaticShell = false,

    // When true, attempt to run build-time instant validation for this export path.
    _runInstantValidation: runInstantValidation = false,

    // Pull the original query out.
    query: originalQuery = {},
  } = exportPath

while (i < resolversAndResults.length) {
  let pendingViewport = resolversAndResults[i++]
  if (typeof pendingViewport === 'function') {
    // this viewport item had a `generateViewport` and
    // we need to provide the currently resolved viewport
    // to it before we continue;
    const resolveParentViewport = pendingViewport
    // we know that the next item is a result if this item
    // was a resolver
    pendingViewport = resolversAndResults[i++] as Result<Viewport>

    resolveParentViewport(freezeInDev(resolvedViewport))
  }
  // Otherwise the item was either null or a static export

  let viewport: Viewport | null
  if (isPromiseLike(pendingViewport)) {
    viewport = await pendingViewport
  } else {
    viewport = pendingViewport
  }

  resolvedViewport = mergeViewport({ resolvedViewport, viewport })
}

useEffect(() => {
    // Handle queued errors.
    errorQueue.forEach(handleOnUnhandledError)
    rejectionQueue.forEach(handleOnUnhandledRejection)

    // Listen to new errors.
    errorHandlers.push(handleOnUnhandledError)
    rejectionHandlers.push(handleOnUnhandledRejection)

    return () => {
      // Remove listeners.
      errorHandlers.splice(errorHandlers.indexOf(handleOnUnhandledError), 1)
      rejectionHandlers.splice(
        rejectionHandlers.indexOf(handleOnUnhandledRejection),
        1
      )

      // Reset error queues.
      errorQueue.splice(0, errorQueue.length)
      rejectionQueue.splice(0, rejectionQueue.length)
    }
  }, [handleOnUnhandledError, handleOnUnhandledRejection])

switch (workUnitStore.type) {
  case 'cache':
  case 'unstable-cache':
    // Inside cache scopes, marking a scope as dynamic has no effect,
    // because the outer cache scope creates a cache boundary. This is
    // subtly different from reading a dynamic data source, which is
    // forbidden inside a cache scope.
    return
  case 'private-cache':
    // A private cache scope is already dynamic by definition.
    return
  case 'prerender':
  case 'prerender-runtime':
  case 'prerender-legacy':
  case 'prerender-ppr':
  case 'prerender-client':
  case 'validation-client':
  case 'generate-static-params':
    break
  case 'request':
    if (process.env.NODE_ENV !== 'production') {
      workUnitStore.usedDynamic = true
    }
    break
  default:
    workUnitStore satisfies never
}

if (!ignoreLoggingIncomingRequests(request, loggingConfig)) {
  logIncomingRequests(
    request,
    requestStartTime,
    requestEndTime,
    response.statusCode,
    devRequestTimingMiddlewareStart,
    devRequestTimingMiddlewareEnd,
    devRequestTimingInternalsEnd,
    devGenerateStaticParamsDuration
  )

  // Log server action after the request log
  const serverActionLog = getRequestMeta(request, 'devServerActionLog')
  if (serverActionLog) {
    const argsStr = formatArgs(serverActionLog.args)
    process.stdout.write(
      `  └─ ƒ ${serverActionLog.functionName}(${argsStr}) in ${serverActionLog.duration}ms ${dim(serverActionLog.location)}\n`
    )
    removeRequestMeta(request, 'devServerActionLog')
  }
}

if (source === 'null') {
  lines.push(
    '',
    'This request came from a privacy-sensitive or opaque origin, so Next.js cannot determine which host to allow.',
    'If you need it to succeed, load the dev server from a normal origin and add that host to "allowedDevOrigins".'
  )
} else if (source) {
  lines.push(
    '',
    'To allow this host in development, add it to "allowedDevOrigins" in next.config.js and restart the dev server:',
    '',
    '// next.config.js',
    'module.exports = {',
    `  allowedDevOrigins: ['${source}'],`,
    '}'
  )
} else {
  lines.push(
    '',
    'This request did not include an allowlistable source host.',
    'If you need it to succeed, make sure the browser sends an Origin or Referer from a host listed in "allowedDevOrigins".'
  )
}

const patchedClearImmediate = (
  immediateObject: NodeJS.Immediate | undefined
) => {
  // NOTE: we defensively check for patched immediates even if we're not
  // currently capturing immediates, because the objects returned from
  // the patched setImmediate can be kept around for arbitrarily long.
  // As an optimization, we only do this if the patch was enabled at least once --
  // otherwise, no patched objects could've been created.
  if (
    wasEnabledAtLeastOnce &&
    immediateObject &&
    typeof immediateObject === 'object' &&
    INTERNALS in immediateObject
  ) {
    ;(immediateObject as NextImmediate)[Symbol.dispose]()
  } else {
    originalClearImmediate(immediateObject)
  }
}

if (requestStore.asyncApiPromises) {
  // We wrap each instance of searchParams in a `new Promise()`.
  // This is important when all awaits are in third party which would otherwise
  // track all the way to the internal params.
  const sharedSearchParamsParent = isRuntimePrefetchable
    ? requestStore.asyncApiPromises.earlySharedSearchParamsParent
    : requestStore.asyncApiPromises.sharedSearchParamsParent
  promise = new Promise((resolve, reject) => {
    sharedSearchParamsParent.then(() => resolve(proxiedUnderlying), reject)
  })
  // @ts-expect-error
  promise.displayName = 'searchParams'
} else {
  promise = makeDevtoolsIOAwarePromise(
    proxiedUnderlying,
    requestStore,
    RenderStage.Runtime
  )
}

if (typeof globalThis.$RefreshInterceptModuleExecution$ === 'function') {
  const cleanupReactRefreshIntercept =
    globalThis.$RefreshInterceptModuleExecution$(module.id)
  try {
    executeModule({
      register: globalThis.$RefreshReg$,
      signature: globalThis.$RefreshSig$,
      registerExports: registerExportsAndSetupBoundaryForReactRefresh,
    })
  } finally {
    // Always cleanup the intercept, even if module execution failed.
    cleanupReactRefreshIntercept()
  }
} else {
  // If the react refresh hooks are not installed we need to bind dummy functions.
  // This is expected when running in a Web Worker.  It is also common in some of
  // our test environments.
  executeModule(DUMMY_REFRESH_CONTEXT)
}

Sentry.init({
  dsn: SENTRY_DSN,
  // Adjust this value in production, or use tracesSampler for greater control
  tracesSampleRate: 1.0,
  // ...
  // Note: if you want to override the automatic release value, do not set a
  // `release` value here - use the environment variable `SENTRY_RELEASE`, so
  // that it will also get attached to your source maps
  // in development and sample at a lower rate in production
  replaysSessionSampleRate: 0.1,

  // If the entire session is not sampled, use the below sample rate to sample
  // sessions when an error occurs.
  replaysOnErrorSampleRate: 1.0,

  integrations: [
    new Sentry.Replay({
      // Additional SDK configuration goes in here, for example:
      maskAllText: true,
      blockAllMedia: true,
    }),
  ],
});

const entry: BFCacheEntry = {
  rsc,
  prefetchRsc,

  // TODO: These fields will be removed from both BFCacheEntry and
  // SegmentCacheEntry. The head has its own separate cache entry.
  head,
  prefetchHead,

  bfcacheId,

  ref: null,
  // TODO: This is just a heuristic. Getting the actual size of the segment
  // isn't feasible because it's part of a larger streaming response. The
  // LRU will still evict it, we just won't have a fully accurate total
  // LRU size. However, we'll probably remove the size tracking from the LRU
  // entirely and use memory pressure events instead.
  size: 100,

  navigatedAt: now,

  // A back/forward navigation will disregard the stale time. This field is
  // only relevant when staleTimes.dynamic is enabled or unstable_dynamicStaleTime
  // is exported by a page.
  staleAt: dynamicStaleAt,
  version: currentBfCacheVersion,
  status: EntryStatus.Fulfilled,
}

if (renderOpts.cacheComponents) {
  // Only run instant validation once per route, even if multiple param sets from generateStaticParams exist.
  const routesWithInstantValidation = new Set<string>()

  for (const exportPath of allExportPaths) {
    if (exportPath._allowEmptyStaticShell) {
      finalPhaseExportPaths.push(exportPath)
    } else {
      initialPhaseExportPaths.push(exportPath)
    }

    // Always mark routes for potential build validation. The actual
    // decision of whether to validate is made per-route by
    // anySegmentNeedsInstantValidationInBuild, which checks both the
    // default validation level and per-segment level overrides.
    const route = exportPath.page
    if (!routesWithInstantValidation.has(route)) {
      exportPath._runInstantValidation = true
      routesWithInstantValidation.add(route)
    }
  }
} else {
  initialPhaseExportPaths = allExportPaths
}

const { prelude: treeStream } = await prerender(
  // RootTreePrefetch is not a valid return type for a React component, but
  // we need to use a component so that when we decode the original stream
  // inside of it, the side effects are transferred to the new stream.
  // @ts-expect-error
  <PrefetchTreeData
    isClientParamParsingEnabled={isCacheComponentsEnabled}
    fullPageDataBuffer={fullPageDataBuffer}
    serverConsumerManifest={serverConsumerManifest}
    clientModules={clientModules}
    staleTime={staleTime}
    segmentTasks={segmentTasks}
    onCompletedProcessingRouteTree={onCompletedProcessingRouteTree}
    prefetchInlining={prefetchInlining}
    hints={hints}
  />,
  clientModules,
  {
    filterStackFrame,
    signal: abortController.signal,
    onError: onSegmentPrerenderError,
  }
)

if (existingSingleton) {
  existingSingleton.clientReferenceManifestsPerRoute.set(
    normalizeAppPath(page),
    clientReferenceManifest
  )

  existingSingleton.serverActionsManifest = serverActionsManifest
} else {
  const clientReferenceManifestsPerRoute = new Map<
    string,
    DeepReadonly<ClientReferenceManifest>
  >([[normalizeAppPath(page), clientReferenceManifest]])

  const proxiedClientReferenceManifest = createProxiedClientReferenceManifest(
    clientReferenceManifestsPerRoute
  )

  globalThisWithManifests[MANIFESTS_SINGLETON] = {
    clientReferenceManifestsPerRoute,
    proxiedClientReferenceManifest,
    serverActionsManifest,
    serverModuleMap: createServerModuleMap(),
  }
}

if (requestStore.asyncApiPromises) {
  const early = isInEarlyRenderStage(requestStore)
  let promise: Promise<ReadonlyRequestCookies>
  if (underlyingCookies === requestStore.mutableCookies) {
    promise = early
      ? requestStore.asyncApiPromises.earlyMutableCookies
      : requestStore.asyncApiPromises.mutableCookies
  } else if (underlyingCookies === requestStore.cookies) {
    promise = early
      ? requestStore.asyncApiPromises.earlyCookies
      : requestStore.asyncApiPromises.cookies
  } else {
    throw new InvariantError(
      'Received an underlying cookies object that does not match either `cookies` or `mutableCookies`'
    )
  }
  return instrumentCookiesPromiseWithDevWarnings(promise, route)
}

for (const fileName of libraryManifestsSupportingNextjsReact) {
  const packageJsonPath = path.join(cwd, fileName)
  const packageJson = await fsp.readFile(packageJsonPath, 'utf-8')
  const manifest = JSON.parse(packageJson)
  // Need to specify last supported RC version to avoid breaking changes.
  if (manifest.peerDependencies['react']) {
    manifest.peerDependencies['react'] = pagesRouterReactVersion
  }
  if (manifest.peerDependencies['react-dom']) {
    manifest.peerDependencies['react-dom'] = pagesRouterReactVersion
  }
  await fsp.writeFile(
    packageJsonPath,
    JSON.stringify(manifest, null, 2) +
      // Prettier would add a newline anyway so do it manually to skip the additional `pnpm prettier-write`
      '\n'
  )
}
